"use strict";function showMenu(){var e=document.getElementById("toggle-icon"),t=document.getElementById("nav-list");e.addEventListener("click",function(){e.classList.toggle("fa-bars"),e.classList.toggle("fa-times"),t.classList.toggle("mobile-open"),t.classList.toggle("mobile-close")}),$(window).resize(function(){575<$(window).width()&&(e.classList.add("fa-bars"),e.classList.remove("fa-times"),t.classList.remove("mobile-open"),t.classList.add("mobile-close"))})}showMenu();var openProject=function(){for(var s=document.getElementsByClassName("project--arrow"),e=function(e){var t=s[e];t.parentElement.addEventListener("click",function(){extendBox(t),changeArrow(t)})},t=0;t<s.length;t++)e(t)};openProject();var extendBox=function(e){var t=e.parentElement.parentElement.querySelector(".project--box");t.classList.toggle("invisible"),t.classList.toggle("visible")},changeArrow=function(e){e.classList.toggle("fa-chevron-down"),e.classList.toggle("fa-chevron-up")};